from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about airports (or related entities) into a single
    fluent, complex sentence. Unknown predicates fall back to a generic phrasing.
    """
    if not triples:
        return ""

    def _clean(val: str) -> str:
        """Remove surrounding quotes if present."""
        return val.strip('"').strip("'")

    # Helper to build a clause for a single triple
    def _clause(s: str, p: str, o: str, include_subject: bool = True) -> str:
        # Primary airport‑specific predicates
        if p == "cityServed":
            return f"{s} serves the city of {o}"
        if p == "location":
            return f"{s} is located in {o}"
        if p == "country":
            return f"{s} is in {o}"
        if p == "isPartOf":
            return f"{s} is part of {o}"
        if p == "elevationAboveTheSeaLevel":
            return f"{s} lies at an elevation of {o} metres above sea level"
        if p == "elevationAboveTheSeaLevelInFeet":
            return f"{s} lies at an elevation of {o} feet above sea level"
        if p == "elevationAboveTheSeaLevelInMetres":
            return f"{s} lies at an elevation of {o} metres above sea level"
        if p == "operatingOrganisation":
            return f"{s} is operated by {o}"
        if p == "runwaySurfaceType":
            return f"{s} has a runway surface of {o}"
        # Runway length variants
        if p.endswith("RunwayLengthFeet"):
            idx = p.split("Runway")[0]
            return f"{s}'s {idx.lower()} runway is {o} feet long"
        if p.endswith("RunwayLengthMetre"):
            idx = p.split("Runway")[0]
            return f"{s}'s {idx.lower()} runway is {o} metres long"
        # Runway identifiers
        if p == "runwayName":
            return f"{s}'s runway is named {o}"
        if p == "runwayLength":
            return f"{s}'s runway length is {o}"
        # Runway surface types
        if p.endswith("RunwaySurfaceType"):
            idx = p.split("Runway")[0]
            return f"{s}'s {idx.lower()} runway surface is {o}"
        # Runway numbers
        if p.endswith("RunwayNumber"):
            idx = p.split("Runway")[0]
            return f"{s}'s {idx.lower()} runway number is {o}"
        # Aviation codes
        if p == "iataLocationIdentifier":
            return f"{s} has IATA code {o}"
        if p == "icaoLocationIdentifier":
            return f"{s} has ICAO code {o}"
        if p == "locationIdentifier":
            return f"{s} has location identifier {o}"
        # Ownership and administration
        if p == "owner":
            return f"{s} is owned by {o}"
        if p == "largestCity":
            return f"The largest city of {s} is {o}"
        if p == "capital":
            return f"The capital of {s} is {o}"
        if p == "language" or p == "officialLanguage":
            return f"The official language of {s} is {o}"
        if p == "leader":
            return f"The leader of {s} is {o}"
        if p == "leaderTitle":
            return f"The leader title of {s} is {o}"
        if p == "leaderParty":
            return f"The leader of {s} belongs to the {o} party"
        # Native name
        if p == "nativeName":
            return f"{s} is known as {o}"
        # Administrative info
        if p == "administrativeArrondissement":
            return f"{s} is in the administrative arrondissement of {o}"
        if p == "mayor":
            return f"The mayor of {s} is {o}"
        if p == "currency":
            return f"{s} uses the {o}"
        if p == "demonym":
            return f"People from {s} are called {o}"
        if p == "regionServed":
            return f"{s} serves the {o} region"
        if p == "hubAirport":
            return f"{o} is a hub airport for {s}"
        if p == "headquarter":
            return f"{s} has its headquarters at {o}"
        if p == "foundedBy":
            return f"{s} was founded by {o}"
        if p == "foundingYear":
            return f"{s} was founded in {o}"
        if p == "postalCode":
            return f"{s} has postal code {o}"
        if p == "areaCode":
            return f"{s} has area code {o}"
        if p == "ceremonialCounty":
            return f"{s} is in the ceremonial county of {o}"
        if p == "countySeat":
            return f"The county seat of {s} is {o}"
        if p == "chief":
            return f"The chief of {s} is {o}"
        if p == "jurisdiction":
            return f"{s} has jurisdiction over {o}"
        if p == "city":
            return f"{s} is located in {o}"
        # Fallback for any other predicate
        return f"{s} has {p} {o}"

    # Build a graph of relationships to chain entities together
    # Map object -> list of triples where this object is the subject
    object_to_subject_triples: dict[str, list[Triple]] = {}
    for t in triples:
        obj = _clean(t.object)
        if obj not in object_to_subject_triples:
            object_to_subject_triples[obj] = []
        object_to_subject_triples[obj].append(t)

    # Find the main subject (airport) - typically the one with cityServed or location predicate
    main_subject = None
    for t in triples:
        if t.predicate in ["cityServed", "location"]:
            main_subject = t.subject
            break
    if not main_subject and triples:
        main_subject = triples[0].subject

    # Group triples by subject for easier processing
    triples_by_subject: dict[str, list[Triple]] = {}
    for t in triples:
        if t.subject not in triples_by_subject:
            triples_by_subject[t.subject] = []
        triples_by_subject[t.subject].append(t)

    # Track which triples we've used
    used_triples: set[int] = set()
    sentence_parts: list[str] = []

    # Process main subject first
    if main_subject and main_subject in triples_by_subject:
        main_triples = triples_by_subject[main_subject]
        for i, t in enumerate(triples):
            if t.subject == main_subject and i not in used_triples:
                clause = _clause(t.subject, t.predicate, _clean(t.object))
                # Remove the subject from clause since it's the main subject
                if clause.startswith(main_subject):
                    rest = clause[len(main_subject):].strip()
                    if rest.startswith(" is ") or rest.startswith(" has ") or rest.startswith(" serves ") or rest.startswith(" lies ") or rest.startswith(" located"):
                        # First clause uses full subject
                        if not sentence_parts:
                            sentence_parts.append(clause)
                        else:
                            sentence_parts.append(f", {rest}")
                    else:
                        if not sentence_parts:
                            sentence_parts.append(clause)
                        else:
                            sentence_parts.append(f", {rest}")
                else:
                    sentence_parts.append(clause)
                used_triples.add(i)

    # Process related entities (where subject is an object from main subject's triples)
    for obj, related_triples in object_to_subject_triples.items():
        if obj in used_triples or obj == main_subject:
            continue
        # Check if this object was mentioned in main subject's triples
        for i, t in enumerate(triples):
            if i in used_triples:
                continue
            if t.subject == obj:
                clause = _clause(t.subject, t.predicate, _clean(t.object))
                # Convert to relative clause
                rest = clause[len(obj):].strip() if clause.startswith(obj) else clause
                if rest.startswith(" is "):
                    rest = rest[4:].strip()
                elif rest.startswith(" has "):
                    rest = rest[5:].strip()
                sentence_parts.append(f", which {rest}")
                used_triples.add(i)

    # Handle any remaining triples
    for i, t in enumerate(triples):
        if i in used_triples:
            continue
        clause = _clause(t.subject, t.predicate, _clean(t.object))
        sentence_parts.append(f", which {clause}")

    # Combine into a single sentence
    if not sentence_parts:
        return ""

    sentence = "".join(sentence_parts)

    # Clean up the sentence
    # Remove double spaces
    while "  " in sentence:
        sentence = sentence.replace("  ", " ")

    # Clean up "which " patterns
    while ", which  " in sentence:
        sentence = sentence.replace(", which  ", ", which ")

    while ", , " in sentence:
        sentence = sentence.replace(", , ", ", ")

    # Ensure proper ending
    sentence = sentence.strip()
    if not sentence.endswith("."):
        sentence += "."

    # Capitalize first letter
    if sentence and sentence[0].islower():
        sentence = sentence[0].upper() + sentence[1:]

    return sentence

# EVOLVE-BLOCK-END

